import React, { useEffect, useState } from 'react';
import { View, Text, Button, Alert } from 'react-native';
import NetInfo from '@react-native-community/netinfo';

const TokenGenerator = () => {
  const [isOnline, setIsOnline] = useState(true);
  const [token, setToken] = useState('');

  useEffect(() => {
    const unsubscribe = NetInfo.addEventListener(state => {
      setIsOnline(state.isConnected);
    });
    return () => unsubscribe();
  }, []);

  const generateToken = () => {
    const newToken = `${Math.random().toString(36).substr(2, 9)}`;
    setToken(newToken);
    Alert.alert('Generated Token', newToken);
  };

  const handleAction = () => {
    if (isOnline) {
      // Perform online action
      Alert.alert('Action performed online');
    } else {
      // Generate token for offline action
      generateToken();
    }
  };

  return (
    <View style={{ padding: 20 }}>
      <Text>{isOnline ? 'You are online' : 'You are offline'}</Text>
      <Button title="Perform Action" onPress={handleAction} />
      {token && <Text>Offline Token: {token}</Text>}
    </View>
  );
};

export default TokenGenerator;